const tz = env.get("ADDON_TIMEZONE") || "UTC";
const contractType = String(env.get("CONTRACT_TYPE") || "fixed").trim();
const currency = String(env.get("CURRENCY") || "EUR").trim();
const lang = String(env.get("DASHBOARD_LANGUAGE") || "en").trim().toLowerCase();
const sendBip = String(env.get("SEND_BIP") || "true") === "true";

const dashboardCustomCardsInstalled = String(env.get("DASHBOARD_CUSTOM_CARDS_INSTALLED") || "false") === "true";
const premiumKey = String(env.get("SMART_ENERGY_FINANCE_PREMIUM_KEY") || env.get("PREMIUM_KEY") || "").trim();
const premiumKeyConfigured = premiumKey.length > 0;

global.set("config.dashboardLanguage", lang === "fr" ? "fr" : "en");
global.set("dashboard.language", lang === "fr" ? "fr" : "en");
global.set("config.dashboardCustomCardsInstalled", dashboardCustomCardsInstalled);
global.set("dashboard.custom_cards_installed", dashboardCustomCardsInstalled);
global.set("config.sendBip", sendBip);
global.set("send_bip", sendBip);
global.set("premium.key", premiumKey);
global.set("premium.key_configured", premiumKeyConfigured);

if (global.get("premium.active") === undefined) global.set("premium.active", false);
if (!global.get("premium.status")) global.set("premium.status", premiumKeyConfigured ? "pending_validation" : "missing_key");
if (global.get("premium.tier") === undefined) global.set("premium.tier", null);

msg.cfg = {
    tz,
    contractType,
    currency,
    lang,
    sendBip,

    monthlySubscriptionPrice: Number(env.get("MONTHLY_SUBSCRIPTION_PRICE") || 0),
    fixedImportPrice: Number(env.get("FIXED_IMPORT_PRICE") || 0),
    fixedExportPrice: Number(env.get("FIXED_EXPORT_PRICE") || 0),

    tariff1: {
        name: String(env.get("TARIFF_1_NAME") || "").trim(),
        price: Number(env.get("TARIFF_1_PRICE") || 0),
        start: String(env.get("TARIFF_1_START") || "").trim(),
        end: String(env.get("TARIFF_1_END") || "").trim()
    },
    tariff2: {
        name: String(env.get("TARIFF_2_NAME") || "").trim(),
        price: Number(env.get("TARIFF_2_PRICE") || 0),
        start: String(env.get("TARIFF_2_START") || "").trim(),
        end: String(env.get("TARIFF_2_END") || "").trim()
    },
    tariff3: {
        name: String(env.get("TARIFF_3_NAME") || "").trim(),
        price: Number(env.get("TARIFF_3_PRICE") || 0),
        start: String(env.get("TARIFF_3_START") || "").trim(),
        end: String(env.get("TARIFF_3_END") || "").trim()
    },
    tariff4: {
        name: String(env.get("TARIFF_4_NAME") || "").trim(),
        price: Number(env.get("TARIFF_4_PRICE") || 0),
        start: String(env.get("TARIFF_4_START") || "").trim(),
        end: String(env.get("TARIFF_4_END") || "").trim()
    },

    tempo: {
        colorEntity: String(env.get("TEMPO_COLOR_ENTITY") || "").trim(),
        blueHc: Number(env.get("TEMPO_BLUE_HC_PRICE") || 0),
        blueHp: Number(env.get("TEMPO_BLUE_HP_PRICE") || 0),
        whiteHc: Number(env.get("TEMPO_WHITE_HC_PRICE") || 0),
        whiteHp: Number(env.get("TEMPO_WHITE_HP_PRICE") || 0),
        redHc: Number(env.get("TEMPO_RED_HC_PRICE") || 0),
        redHp: Number(env.get("TEMPO_RED_HP_PRICE") || 0),
        hcSlot1Start: String(env.get("TEMPO_HC_SLOT_1_START") || "22:00").trim(),
        hcSlot1End: String(env.get("TEMPO_HC_SLOT_1_END") || "06:00").trim(),
        hcSlot2Start: String(env.get("TEMPO_HC_SLOT_2_START") || "").trim(),
        hcSlot2End: String(env.get("TEMPO_HC_SLOT_2_END") || "").trim()
    },

    solarEnabled: String(env.get("SOLAR_ENABLED") || "false") === "true",
    solarInputMode: String(env.get("SOLAR_INPUT_MODE") || "energy").trim(),
    solarEnergyEntity: String(env.get("SOLAR_ENERGY_ENTITY") || "").trim(),
    solarPowerEntity: String(env.get("SOLAR_POWER_ENTITY") || "").trim(),

    loadEnabled: String(env.get("LOAD_ENABLED") || "false") === "true",
    loadInputMode: String(env.get("LOAD_INPUT_MODE") || "energy").trim(),
    loadEnergyEntity: String(env.get("LOAD_ENERGY_ENTITY") || "").trim(),
    loadPowerEntity: String(env.get("LOAD_POWER_ENTITY") || "").trim(),

    batteryEnabled: String(env.get("BATTERY_ENABLED") || "false") === "true",
    batteryInputMode: String(env.get("BATTERY_INPUT_MODE") || "energy").trim(),
    batteryChargeEnergyEntity: String(env.get("BATTERY_CHARGE_ENERGY_ENTITY") || "").trim(),
    batteryDischargeEnergyEntity: String(env.get("BATTERY_DISCHARGE_ENERGY_ENTITY") || "").trim(),
    batteryChargePowerEntity: String(env.get("BATTERY_CHARGE_POWER_ENTITY") || "").trim(),
    batteryDischargePowerEntity: String(env.get("BATTERY_DISCHARGE_POWER_ENTITY") || "").trim(),
    batteryCapacityAh: Number(env.get("BATTERY_CAPACITY_AH") || 0),
    batteryTotalCapacityKwh: Number(env.get("BATTERY_TOTAL_CAPACITY_KWH") || 0),

    gridEnabled: String(env.get("GRID_ENABLED") || "false") === "true",
    gridInputMode: String(env.get("GRID_INPUT_MODE") || "energy").trim(),
    gridImportEnergyEntity: String(env.get("GRID_IMPORT_ENERGY_ENTITY") || "").trim(),
    gridExportEnergyEntity: String(env.get("GRID_EXPORT_ENERGY_ENTITY") || "").trim(),
    gridImportPowerEntity: String(env.get("GRID_IMPORT_POWER_ENTITY") || "").trim(),
    gridExportPowerEntity: String(env.get("GRID_EXPORT_POWER_ENTITY") || "").trim()
};

return msg;

const token = env.get("SUPERVISOR_TOKEN") || "";
if (!token) {
    node.error("SUPERVISOR_TOKEN introuvable");
    return null;
}

msg.method = "GET";
msg.url = "http://supervisor/core/api/states";
msg.headers = {
    Authorization: `Bearer ${token}`,
    "Content-Type": "application/json"
};
return msg;

const cfg = msg.cfg;
const list = Array.isArray(msg.payload) ? msg.payload : [];

const states = {};
for (const item of list) {
    if (item && item.entity_id) states[item.entity_id] = item;
}

function num(entityId) {
    if (!entityId || !states[entityId]) return 0;
    const n = Number(states[entityId].state);
    return Number.isFinite(n) ? n : 0;
}

function str(entityId) {
    if (!entityId || !states[entityId]) return "";
    return String(states[entityId].state || "").trim();
}

msg.inputs = {
    solarDay: cfg.solarEnabled && cfg.solarInputMode === "energy" ? num(cfg.solarEnergyEntity) : 0,
    loadDay: cfg.loadEnabled && cfg.loadInputMode === "energy" ? num(cfg.loadEnergyEntity) : 0,
    gridImportDay: cfg.gridEnabled && cfg.gridInputMode === "energy" ? num(cfg.gridImportEnergyEntity) : 0,
    gridExportDay: cfg.gridEnabled && cfg.gridInputMode === "energy" ? num(cfg.gridExportEnergyEntity) : 0,
    batteryChargeDay: cfg.batteryEnabled && cfg.batteryInputMode === "energy" ? num(cfg.batteryChargeEnergyEntity) : 0,
    batteryDischargeDay: cfg.batteryEnabled && cfg.batteryInputMode === "energy" ? num(cfg.batteryDischargeEnergyEntity) : 0,

    solarPower: cfg.solarEnabled && cfg.solarInputMode === "power" ? num(cfg.solarPowerEntity) : 0,
    loadPower: cfg.loadEnabled && cfg.loadInputMode === "power" ? num(cfg.loadPowerEntity) : 0,
    gridImportPower: cfg.gridEnabled && cfg.gridInputMode === "power" ? num(cfg.gridImportPowerEntity) : 0,
    gridExportPower: cfg.gridEnabled && cfg.gridInputMode === "power" ? num(cfg.gridExportPowerEntity) : 0,
    batteryChargePower: cfg.batteryEnabled && cfg.batteryInputMode === "power" ? num(cfg.batteryChargePowerEntity) : 0,
    batteryDischargePower: cfg.batteryEnabled && cfg.batteryInputMode === "power" ? num(cfg.batteryDischargePowerEntity) : 0,

    tempoColorRaw: cfg.contractType === "tempo" ? str(cfg.tempo.colorEntity) : ""
};

return msg;

const cfg = msg.cfg;
const inputs = msg.inputs || {};
const premiumActive = global.get("premium.active") === true;

function round(v, d = 2) {
    return Number((Number(v || 0)).toFixed(d));
}

function hhmmToMinutes(s) {
    if (!s || !/^\d{2}:\d{2}$/.test(s)) return null;
    const [h, m] = s.split(":").map(Number);
    if (!Number.isInteger(h) || !Number.isInteger(m)) return null;
    if (h < 0 || h > 23 || m < 0 || m > 59) return null;
    return h * 60 + m;
}

function minuteOfDay(t) {
    return (Number(t.hour) * 60) + Number(t.minute);
}

function isMinuteInRange(minute, start, end) {
    const s = hhmmToMinutes(start);
    const e = hhmmToMinutes(end);
    if (s === null || e === null) return false;
    if (s === e) return true;
    if (s < e) return minute >= s && minute < e;
    return minute >= s || minute < e;
}

function normalizeTempoColor(v) {
    const s = String(v || "").trim().toLowerCase();
    if (s === "bleu") return "blue";
    if (s === "blanc") return "white";
    if (s === "rouge") return "red";
    if (s === "blue") return "blue";
    if (s === "white") return "white";
    if (s === "red") return "red";
    return "unknown";
}

function isTempoHc(minute, tempoCfg) {
    return (
        isMinuteInRange(minute, tempoCfg.hcSlot1Start, tempoCfg.hcSlot1End) ||
        (tempoCfg.hcSlot2Start && tempoCfg.hcSlot2End && isMinuteInRange(minute, tempoCfg.hcSlot2Start, tempoCfg.hcSlot2End))
    );
}

function dateParts(tz) {
    const parts = new Intl.DateTimeFormat("en-CA", {
        timeZone: tz,
        year: "numeric",
        month: "2-digit",
        day: "2-digit",
        hour: "2-digit",
        minute: "2-digit",
        second: "2-digit",
        hour12: false
    }).formatToParts(new Date());

    const m = {};
    for (const p of parts) {
        if (p.type !== "literal") m[p.type] = p.value;
    }

    return {
        year: m.year,
        month: m.month,
        day: m.day,
        hour: m.hour,
        minute: m.minute,
        second: m.second,
        dayKey: `${m.year}-${m.month}-${m.day}`,
        monthKey: `${m.year}-${m.month}`,
        yearKey: `${m.year}`
    };
}

function emptyEnergy() {
    return {
        solar: 0,
        load: 0,
        gridImport: 0,
        gridExport: 0,
        batteryCharge: 0,
        batteryDischarge: 0
    };
}

function emptyFinance() {
    return {
        import_cost: 0,
        export_revenue: 0,
        theoretical_no_solar_cost: 0,
        solar_production_value: 0,
        battery_discharge_value: 0,
        home_supply_savings: 0
    };
}

function currentDaySnapshot(inputs) {
    return {
        solar: Number(inputs.solarDay || 0),
        load: Number(inputs.loadDay || 0),
        gridImport: Number(inputs.gridImportDay || 0),
        gridExport: Number(inputs.gridExportDay || 0),
        batteryCharge: Number(inputs.batteryChargeDay || 0),
        batteryDischarge: Number(inputs.batteryDischargeDay || 0)
    };
}

function safeEnergyValue(v) {
    const n = Number(v);
    return Number.isFinite(n) && n >= 0 ? n : 0;
}

function sanitizeEnergySnapshot(s) {
    return {
        solar: safeEnergyValue(s && s.solar),
        load: safeEnergyValue(s && s.load),
        gridImport: safeEnergyValue(s && s.gridImport),
        gridExport: safeEnergyValue(s && s.gridExport),
        batteryCharge: safeEnergyValue(s && s.batteryCharge),
        batteryDischarge: safeEnergyValue(s && s.batteryDischarge)
    };
}

function sumEnergy(s) {
    return (
        Number(s.solar || 0) +
        Number(s.load || 0) +
        Number(s.gridImport || 0) +
        Number(s.gridExport || 0) +
        Number(s.batteryCharge || 0) +
        Number(s.batteryDischarge || 0)
    );
}

function addEnergy(a, b) {
    return {
        solar: round(Number(a.solar || 0) + Number(b.solar || 0), 6),
        load: round(Number(a.load || 0) + Number(b.load || 0), 6),
        gridImport: round(Number(a.gridImport || 0) + Number(b.gridImport || 0), 6),
        gridExport: round(Number(a.gridExport || 0) + Number(b.gridExport || 0), 6),
        batteryCharge: round(Number(a.batteryCharge || 0) + Number(b.batteryCharge || 0), 6),
        batteryDischarge: round(Number(a.batteryDischarge || 0) + Number(b.batteryDischarge || 0), 6)
    };
}

function addFinance(a, b) {
    return {
        import_cost: round(Number(a.import_cost || 0) + Number(b.import_cost || 0), 6),
        export_revenue: round(Number(a.export_revenue || 0) + Number(b.export_revenue || 0), 6),
        theoretical_no_solar_cost: round(Number(a.theoretical_no_solar_cost || 0) + Number(b.theoretical_no_solar_cost || 0), 6),
        solar_production_value: round(Number(a.solar_production_value || 0) + Number(b.solar_production_value || 0), 6),
        battery_discharge_value: round(Number(a.battery_discharge_value || 0) + Number(b.battery_discharge_value || 0), 6),
        home_supply_savings: round(Number(a.home_supply_savings || 0) + Number(b.home_supply_savings || 0), 6)
    };
}

function proratedSubscription(periodName, monthlyPrice, time) {
    const p = Number(monthlyPrice || 0);
    if (!p) return 0;
    if (periodName === "day") {
        const daysInMonth = new Date(Number(time.year), Number(time.month), 0).getDate();
        return p / daysInMonth;
    }
    if (periodName === "month") return p;
    if (periodName === "year") return p * 12;
    return 0;
}

function buildPeriodFinance(accEnergy, accFinance, periodName, cfg, now) {
    const importEnergy = Number(accEnergy.gridImport || 0);
    const exportEnergy = Number(accEnergy.gridExport || 0);
    const loadEnergy = Number(accEnergy.load || 0);
    const solarEnergy = Number(accEnergy.solar || 0);
    const batteryCharge = Number(accEnergy.batteryCharge || 0);
    const batteryDischarge = Number(accEnergy.batteryDischarge || 0);

    const importCost = Number(accFinance.import_cost || 0);
    const exportRevenue = Number(accFinance.export_revenue || 0);
    const theoreticalNoSolarCost = Number(accFinance.theoretical_no_solar_cost || 0);
    const solarProductionValue = Number(accFinance.solar_production_value || 0);
    const batteryDischargeValue = Number(accFinance.battery_discharge_value || 0);
    const homeSupplySavings = Number(accFinance.home_supply_savings || 0);

    const subscriptionCost = proratedSubscription(periodName, cfg.monthlySubscriptionPrice, now);
    const realTotalWithSubscription = importCost + subscriptionCost - exportRevenue;
    const savingsVsNoSolar = theoreticalNoSolarCost - importCost + exportRevenue;

    let selfSufficiencyPct = 0;
    if (loadEnergy > 0) {
        selfSufficiencyPct = ((Math.max(0, loadEnergy - importEnergy)) / loadEnergy) * 100;
    }

    let gridDependencyPct = 0;
    if (loadEnergy > 0) {
        gridDependencyPct = (importEnergy / loadEnergy) * 100;
    }

    return {
        energy: {
            solar_kwh: round(solarEnergy),
            load_kwh: round(loadEnergy),
            grid_import_kwh: round(importEnergy),
            grid_export_kwh: round(exportEnergy),
            battery_charge_kwh: round(batteryCharge),
            battery_discharge_kwh: round(batteryDischarge)
        },
        finance: {
            import_cost: round(importCost),
            export_revenue: round(exportRevenue),
            subscription_cost: round(subscriptionCost),
            theoretical_no_solar_cost: round(theoreticalNoSolarCost),
            solar_production_value: round(solarProductionValue),
            battery_discharge_value: round(batteryDischargeValue),
            home_supply_savings: round(homeSupplySavings),
            real_total_with_subscription: round(realTotalWithSubscription),
            savings_vs_no_solar: round(savingsVsNoSolar)
        },
        ratios: {
            self_sufficiency_pct: round(selfSufficiencyPct, 2),
            grid_dependency_pct: round(gridDependencyPct, 2)
        }
    };
}

function clone(v) {
    return JSON.parse(JSON.stringify(v));
}

function trimHistory(arr, maxLen) {
    const a = Array.isArray(arr) ? arr : [];
    while (a.length > maxLen) a.shift();
    return a;
}

function makeHistoryEntry(key, periodData) {
    return {
        key,
        import_cost: round(periodData.finance.import_cost),
        export_revenue: round(periodData.finance.export_revenue),
        theoretical_no_solar_cost: round(periodData.finance.theoretical_no_solar_cost),
        solar_production_value: round(periodData.finance.solar_production_value),
        battery_discharge_value: round(periodData.finance.battery_discharge_value),
        home_supply_savings: round(periodData.finance.home_supply_savings),
        real_total_with_subscription: round(periodData.finance.real_total_with_subscription),
        savings_vs_no_solar: round(periodData.finance.savings_vs_no_solar),
        grid_import_kwh: round(periodData.energy.grid_import_kwh),
        grid_export_kwh: round(periodData.energy.grid_export_kwh),
        solar_kwh: round(periodData.energy.solar_kwh),
        load_kwh: round(periodData.energy.load_kwh),
        battery_charge_kwh: round(periodData.energy.battery_charge_kwh),
        battery_discharge_kwh: round(periodData.energy.battery_discharge_kwh),
        self_sufficiency_pct: round(periodData.ratios.self_sufficiency_pct, 2),
        grid_dependency_pct: round(periodData.ratios.grid_dependency_pct, 2)
    };
}

function diff(cur, prev) {
    return round(Number(cur || 0) - Number(prev || 0), 6);
}

function buildDeltaWithProtection(cur, prev, store, nowMs) {
    const fields = ["solar", "load", "gridImport", "gridExport", "batteryCharge", "batteryDischarge"];
    const delta = emptyEnergy();

    const lastRunMs = Number(store.runtime.lastRunMs || 0);
    const elapsedSec = lastRunMs > 0 ? Math.max(10, (nowMs - lastRunMs) / 1000) : 10;

    const longGap = elapsedSec > 300;
    const jumpFactor = 1.5;

    let hasReset = false;
    let hasProgress = false;
    let hasImpossibleJump = false;
    let impossibleField = "";

    const curSum = sumEnergy(cur);
    const prevSum = sumEnergy(prev);

    if (curSum === 0 && prevSum > 0) {
        return {
            delta,
            hasReset: false,
            hasProgress: false,
            hasImpossibleJump: true,
            impossibleField: "all_zero_after_restart",
            keepPreviousBaseline: true
        };
    }

    for (const f of fields) {
        const c = Number(cur[f] || 0);
        const p = Number(prev[f] || 0);
        const d = diff(c, p);

        if (d < 0) {
            hasReset = true;
            delta[f] = 0;
            continue;
        }

        if (!longGap && p > 1 && c > (p * jumpFactor)) {
            hasImpossibleJump = true;
            impossibleField = f;
            delta[f] = 0;
            continue;
        }

        delta[f] = d;
        if (d > 0) hasProgress = true;
    }

    return {
        delta,
        hasReset,
        hasProgress,
        hasImpossibleJump,
        impossibleField,
        keepPreviousBaseline: false
    };
}

function applyLiveFinanceFloor(store, liveDay, tariff) {
    const importPrice = Number(tariff.importPrice || 0);
    if (importPrice <= 0) return;

    const load = Number(liveDay.load || 0);
    const gridImport = Number(liveDay.gridImport || 0);

    if (load <= 0) return;
    if (gridImport < 0) return;
    if (gridImport > load * 1.5) return;

    const liveMinimumSavings = Math.max(0, load - gridImport) * importPrice;

    if (
        liveMinimumSavings > 0 &&
        liveMinimumSavings > Number(store.currentDayFinanceAccumulator.home_supply_savings || 0)
    ) {
        store.currentDayFinanceAccumulator.home_supply_savings = round(liveMinimumSavings, 6);
        store.runtime.lastRebaseReason = "live_finance_floor_home_supply_savings";
        store.runtime.lastRebaseAt = new Date().toISOString();
    }
}

const now = dateParts(cfg.tz || "UTC");
const nowMs = Date.now();
const liveDay = sanitizeEnergySnapshot(currentDaySnapshot(inputs));

function createDefaultStore() {
    return {
        keys: { dayKey: now.dayKey, monthKey: now.monthKey, yearKey: now.yearKey },
        prevLiveDay: liveDay,
        closedDayMonthAccumulator: emptyEnergy(),
        closedDayYearAccumulator: emptyEnergy(),
        currentDayFinanceAccumulator: emptyFinance(),
        closedDayMonthFinanceAccumulator: emptyFinance(),
        closedDayYearFinanceAccumulator: emptyFinance(),
        currentDaySnapshot: liveDay,
        lastClosedDayKey: "",
        runtime: {
            initialized: false,
            lastRebaseReason: "",
            lastRebaseAt: "",
            lastRunMs: 0,
            restartGuardUntilMs: 0,
            maxAcceptedPowerKw: 60
        },
        history: {
            daily: [],
            monthly: [],
            yearly: [],
            lastArchivedMonthKey: "",
            lastArchivedYearKey: ""
        },
        meta: {
            lastTempoColor: "",
            lastTariffName: "",
            lastTariffPeriod: "",
            lastRun: ""
        }
    };
}

const flowStore = flow.get("finance_store", "persistent");
const globalStore = global.get("sef.persisted_store");

let store = flowStore || globalStore;

const flowCorrectionAt = String(flowStore?.meta?.lastManualCorrectionAt || "");
const globalCorrectionAt = String(globalStore?.meta?.lastManualCorrectionAt || "");

if (globalStore && globalCorrectionAt && globalCorrectionAt > flowCorrectionAt) {
    store = globalStore;
}
if (!store || typeof store !== "object") {
    store = createDefaultStore();
}

store.history = store.history || {};
store.history.daily = Array.isArray(store.history.daily) ? store.history.daily : [];
store.history.monthly = Array.isArray(store.history.monthly) ? store.history.monthly : [];
store.history.yearly = Array.isArray(store.history.yearly) ? store.history.yearly : [];
store.history.lastArchivedMonthKey = String(store.history.lastArchivedMonthKey || "");
store.history.lastArchivedYearKey = String(store.history.lastArchivedYearKey || "");

store.runtime = store.runtime || {};
store.runtime.initialized = store.runtime.initialized === true;
store.runtime.lastRebaseReason = String(store.runtime.lastRebaseReason || "");
store.runtime.lastRebaseAt = String(store.runtime.lastRebaseAt || "");
store.runtime.lastRunMs = Number(store.runtime.lastRunMs || 0);
store.runtime.restartGuardUntilMs = Number(store.runtime.restartGuardUntilMs || 0);
store.runtime.maxAcceptedPowerKw = Number(store.runtime.maxAcceptedPowerKw || 60);

if (msg.restore && msg.restore.financeStoreRestored === true) {
    store.runtime.restartGuardUntilMs = nowMs + 120000;
    store.runtime.lastRebaseReason = "restore_guard_started";
    store.runtime.lastRebaseAt = new Date().toISOString();
}

store.prevLiveDay = sanitizeEnergySnapshot(store.prevLiveDay || emptyEnergy());
store.currentDaySnapshot = sanitizeEnergySnapshot(store.currentDaySnapshot || emptyEnergy());
store.closedDayMonthAccumulator = sanitizeEnergySnapshot(store.closedDayMonthAccumulator || emptyEnergy());
store.closedDayYearAccumulator = sanitizeEnergySnapshot(store.closedDayYearAccumulator || emptyEnergy());
store.currentDayFinanceAccumulator = store.currentDayFinanceAccumulator || emptyFinance();
store.closedDayMonthFinanceAccumulator = store.closedDayMonthFinanceAccumulator || emptyFinance();
store.closedDayYearFinanceAccumulator = store.closedDayYearFinanceAccumulator || emptyFinance();

const oldDayKey = String(store.keys?.dayKey || now.dayKey);
const oldMonthKey = String(store.keys?.monthKey || now.monthKey);
const oldYearKey = String(store.keys?.yearKey || now.yearKey);

function getCurrentTariff() {
    const minute = minuteOfDay(now);

    if (cfg.contractType === "fixed") {
        return {
            mode: "fixed",
            name: "fixed",
            period: "fixed",
            importPrice: Number(cfg.fixedImportPrice || 0),
            exportPrice: Number(cfg.fixedExportPrice || 0),
            tempoColor: "",
            tempoColorRaw: "",
            isTempoHc: false
        };
    }

    if (cfg.contractType === "time_based") {
        const tariffs = [cfg.tariff1, cfg.tariff2, cfg.tariff3, cfg.tariff4]
            .filter(t => t && t.name && t.start && t.end);

        for (const t of tariffs) {
            if (isMinuteInRange(minute, t.start, t.end)) {
                return {
                    mode: "time_based",
                    name: t.name,
                    period: t.name,
                    importPrice: Number(t.price || 0),
                    exportPrice: Number(cfg.fixedExportPrice || 0),
                    tempoColor: "",
                    tempoColorRaw: "",
                    isTempoHc: false
                };
            }
        }

        return {
            mode: "time_based",
            name: "unmatched",
            period: "unmatched",
            importPrice: 0,
            exportPrice: Number(cfg.fixedExportPrice || 0),
            tempoColor: "",
            tempoColorRaw: "",
            isTempoHc: false
        };
    }

    if (cfg.contractType === "tempo") {
        const colorRaw = String(inputs.tempoColorRaw || "").trim();
        const color = normalizeTempoColor(colorRaw);
        const hc = isTempoHc(minute, cfg.tempo);

        let importPrice = 0;
        let name = "tempo_unknown";
        const period = hc ? "hc" : "hp";

        if (color === "blue") {
            importPrice = hc ? Number(cfg.tempo.blueHc || 0) : Number(cfg.tempo.blueHp || 0);
            name = hc ? "tempo_blue_hc" : "tempo_blue_hp";
        } else if (color === "white") {
            importPrice = hc ? Number(cfg.tempo.whiteHc || 0) : Number(cfg.tempo.whiteHp || 0);
            name = hc ? "tempo_white_hc" : "tempo_white_hp";
        } else if (color === "red") {
            importPrice = hc ? Number(cfg.tempo.redHc || 0) : Number(cfg.tempo.redHp || 0);
            name = hc ? "tempo_red_hc" : "tempo_red_hp";
        }

        return {
            mode: "tempo",
            name,
            period,
            importPrice,
            exportPrice: Number(cfg.fixedExportPrice || 0),
            tempoColor: color,
            tempoColorRaw: colorRaw || "inconnu",
            isTempoHc: hc
        };
    }

    return {
        mode: "fixed",
        name: "fixed",
        period: "fixed",
        importPrice: Number(cfg.fixedImportPrice || 0),
        exportPrice: Number(cfg.fixedExportPrice || 0),
        tempoColor: "",
        tempoColorRaw: "",
        isTempoHc: false
    };
}

const tariff = getCurrentTariff();

if (oldDayKey !== now.dayKey) {
    if (store.lastClosedDayKey !== oldDayKey) {
        const closedDayData = buildPeriodFinance(
            clone(store.currentDaySnapshot || emptyEnergy()),
            clone(store.currentDayFinanceAccumulator || emptyFinance()),
            "day",
            cfg,
            {
                year: oldDayKey.slice(0, 4),
                month: oldDayKey.slice(5, 7),
                day: oldDayKey.slice(8, 10)
            }
        );

        store.history.daily.push(makeHistoryEntry(oldDayKey, closedDayData));
        store.history.daily = trimHistory(store.history.daily, 62);

        store.closedDayMonthAccumulator = addEnergy(store.closedDayMonthAccumulator, store.currentDaySnapshot);
        store.closedDayYearAccumulator = addEnergy(store.closedDayYearAccumulator, store.currentDaySnapshot);
        store.closedDayMonthFinanceAccumulator = addFinance(store.closedDayMonthFinanceAccumulator, store.currentDayFinanceAccumulator);
        store.closedDayYearFinanceAccumulator = addFinance(store.closedDayYearFinanceAccumulator, store.currentDayFinanceAccumulator);
        store.lastClosedDayKey = oldDayKey;
    }

    if (oldMonthKey !== now.monthKey) {
        if (store.history.lastArchivedMonthKey !== oldMonthKey) {
            const closedMonthData = buildPeriodFinance(
                clone(store.closedDayMonthAccumulator || emptyEnergy()),
                clone(store.closedDayMonthFinanceAccumulator || emptyFinance()),
                "month",
                cfg,
                {
                    year: oldMonthKey.slice(0, 4),
                    month: oldMonthKey.slice(5, 7)
                }
            );

            store.history.monthly.push(makeHistoryEntry(oldMonthKey, closedMonthData));
            store.history.monthly = trimHistory(store.history.monthly, 24);
            store.history.lastArchivedMonthKey = oldMonthKey;
        }

        store.closedDayMonthAccumulator = emptyEnergy();
        store.closedDayMonthFinanceAccumulator = emptyFinance();
    }

    if (oldYearKey !== now.yearKey) {
        if (store.history.lastArchivedYearKey !== oldYearKey) {
            const closedYearData = buildPeriodFinance(
                clone(store.closedDayYearAccumulator || emptyEnergy()),
                clone(store.closedDayYearFinanceAccumulator || emptyFinance()),
                "year",
                cfg,
                { year: oldYearKey }
            );

            store.history.yearly.push(makeHistoryEntry(oldYearKey, closedYearData));
            store.history.yearly = trimHistory(store.history.yearly, 10);
            store.history.lastArchivedYearKey = oldYearKey;
        }

        store.closedDayYearAccumulator = emptyEnergy();
        store.closedDayYearFinanceAccumulator = emptyFinance();
    }

    store.currentDayFinanceAccumulator = emptyFinance();
    store.prevLiveDay = liveDay;
    store.currentDaySnapshot = liveDay;
    store.runtime.initialized = true;
    store.runtime.lastRebaseReason = "new_day";
    store.runtime.lastRebaseAt = new Date().toISOString();
    store.runtime.restartGuardUntilMs = nowMs + 60000;
}

if (oldDayKey === now.dayKey) {
    if (!store.runtime.initialized) {
        store.prevLiveDay = liveDay;
        store.currentDaySnapshot = liveDay;
        store.runtime.initialized = true;
        store.runtime.lastRebaseReason = "startup_init";
        store.runtime.lastRebaseAt = new Date().toISOString();
        store.runtime.restartGuardUntilMs = nowMs + 120000;
    } else {
        const inRestartGuard = nowMs < Number(store.runtime.restartGuardUntilMs || 0);
        const calc = buildDeltaWithProtection(liveDay, store.prevLiveDay || emptyEnergy(), store, nowMs);
        const delta = calc.delta;

        if (inRestartGuard) {
            store.prevLiveDay = liveDay;
            store.currentDaySnapshot = liveDay;
            store.runtime.lastRebaseReason = "restart_guard_rebase";
            store.runtime.lastRebaseAt = new Date().toISOString();
            node.status({ fill: "yellow", shape: "ring", text: "restart guard: baseline only" });

        } else if (calc.keepPreviousBaseline) {
            store.currentDaySnapshot = store.currentDaySnapshot || store.prevLiveDay;
            store.runtime.lastRebaseReason = "ignored_zero_states_after_restart";
            store.runtime.lastRebaseAt = new Date().toISOString();
            node.status({ fill: "yellow", shape: "ring", text: "ignored temporary zero states" });

        } else if (calc.hasReset) {
            store.prevLiveDay = liveDay;
            store.currentDaySnapshot = liveDay;
            store.runtime.lastRebaseReason = "counter_reset_or_restart";
            store.runtime.lastRebaseAt = new Date().toISOString();
            node.status({ fill: "yellow", shape: "ring", text: "rebase after reset/restart" });

        } else if (calc.hasImpossibleJump) {
            store.prevLiveDay = liveDay;
            store.currentDaySnapshot = liveDay;
            store.runtime.lastRebaseReason = `ignored_impossible_jump_${calc.impossibleField || "unknown"}`;
            store.runtime.lastRebaseAt = new Date().toISOString();
            node.status({ fill: "red", shape: "ring", text: `ignored spike ${calc.impossibleField || ""}` });

        } else {
            store.currentDayFinanceAccumulator.import_cost = round(
                Number(store.currentDayFinanceAccumulator.import_cost || 0) +
                Number(delta.gridImport || 0) * Number(tariff.importPrice || 0),
                6
            );

            store.currentDayFinanceAccumulator.export_revenue = round(
                Number(store.currentDayFinanceAccumulator.export_revenue || 0) +
                Number(delta.gridExport || 0) * Number(tariff.exportPrice || 0),
                6
            );

            store.currentDayFinanceAccumulator.theoretical_no_solar_cost = round(
                Number(store.currentDayFinanceAccumulator.theoretical_no_solar_cost || 0) +
                Number(delta.load || 0) * Number(tariff.importPrice || 0),
                6
            );

            store.currentDayFinanceAccumulator.solar_production_value = round(
                Number(store.currentDayFinanceAccumulator.solar_production_value || 0) +
                Number(delta.solar || 0) * Number(tariff.importPrice || 0),
                6
            );

            store.currentDayFinanceAccumulator.battery_discharge_value = round(
                Number(store.currentDayFinanceAccumulator.battery_discharge_value || 0) +
                Number(delta.batteryDischarge || 0) * Number(tariff.importPrice || 0),
                6
            );

            const coveredBySystem = Math.max(0, Number(delta.load || 0) - Number(delta.gridImport || 0));
            store.currentDayFinanceAccumulator.home_supply_savings = round(
                Number(store.currentDayFinanceAccumulator.home_supply_savings || 0) +
                coveredBySystem * Number(tariff.importPrice || 0),
                6
            );

            store.prevLiveDay = liveDay;
            store.currentDaySnapshot = liveDay;

            if (cfg.contractType === "tempo") {
                node.status({
                    fill: tariff.tempoColor === "unknown" ? "grey" : "green",
                    shape: "dot",
                    text: `tempo ${tariff.tempoColorRaw || "inconnu"} / ${tariff.period}`
                });
            } else {
                node.status({ fill: "blue", shape: "dot", text: `${cfg.contractType} / ${tariff.name}` });
            }
        }
    }
}

applyLiveFinanceFloor(store, liveDay, tariff);

store.keys = {
    dayKey: now.dayKey,
