            },
            finance: {
                import_cost: required,
                export_revenue: required,
                subscription_cost: required,
                theoretical_no_solar_cost: required,
                solar_production_value: required,
                battery_discharge_value: required,
                home_supply_savings: required,
                real_total_with_subscription: required,
                savings_vs_no_solar: required
            },
            ratios: {
                self_sufficiency_pct: required,
                grid_dependency_pct: required
            }
        },
        year: {
            energy: {
                solar_kwh: required,
                load_kwh: required,
                grid_import_kwh: required,
                grid_export_kwh: required,
                battery_charge_kwh: required,
                battery_discharge_kwh: required
            },
            finance: {
                import_cost: required,
                export_revenue: required,
                subscription_cost: required,
                theoretical_no_solar_cost: required,
                solar_production_value: required,
                battery_discharge_value: required,
                home_supply_savings: required,
                real_total_with_subscription: required,
                savings_vs_no_solar: required
            },
            ratios: {
                self_sufficiency_pct: required,
                grid_dependency_pct: required
            }
        },
        battery: {
            day_charge_kwh: required,
            day_discharge_kwh: required,
            day_discharge_value: required,
            month_charge_kwh: required,
            month_discharge_kwh: required,
            month_discharge_value: required,
            year_charge_kwh: required,
            year_discharge_kwh: required,
            year_discharge_value: required
        },
        history: {
            daily: [],
            monthly: [],
            yearly: []
        }
    };

    node.status({
        fill: "grey",
        shape: "ring",
        text: "premium inactif"
    });
}

delete msg.sef;
return msg;

let restored = false;
let restoreStatus = "no_store_file";

if (msg.payload !== undefined && msg.payload !== null && msg.payload !== "") {
    try {
        const parsed = (typeof msg.payload === "string") ? JSON.parse(msg.payload) : msg.payload;

        if (parsed && typeof parsed === "object") {
            global.set("sef.persisted_store", parsed);
            flow.set("finance_store", parsed, "persistent");
            restored = true;
            restoreStatus = "restored";
