        } else {
            restoreStatus = "invalid_store_object";
            node.status({ fill: "yellow", shape: "ring", text: "invalid finance store object" });
        }
    } catch (e) {
        restoreStatus = "restore_parse_error";
        node.warn("Unable to restore persistent finance store: " + e.message);
        node.status({ fill: "yellow", shape: "ring", text: "finance store restore parse error" });
    }
} else {
    node.status({ fill: "grey", shape: "ring", text: "no finance store file" });
}

msg.restore = {
    financeStoreRestored: restored,
    financeStoreRestoreStatus: restoreStatus,
    restoredAt: new Date().toISOString()
};

