function stableObjectId(objectId) {
  return `smart_energy_finance_${objectId}`;
}

function discoveryTopic(domain, objectId) {
  const uid = stableObjectId(objectId);
  return `${discoveryPrefix}/${domain}/${uid}/config`;
}

function sensor(objectId, name, valueTemplate, options = {}) {
  const uid = stableObjectId(objectId);
  const payload = {
    name,
    unique_id: uid,
    object_id: uid,
    default_entity_id: `sensor.${uid}`,
    state_topic: stateTopic,
    availability_topic: availabilityTopic,
    payload_available: "online",
    payload_not_available: "offline",
    value_template: valueTemplate,
    force_update: true,
    device
  };

  if (options.icon) payload.icon = options.icon;
  if (options.unit) payload.unit_of_measurement = options.unit;
  if (options.deviceClass) payload.device_class = options.deviceClass;
  if (options.stateClass) payload.state_class = options.stateClass;
  if (options.entityCategory) payload.entity_category = options.entityCategory;
  if (options.enabledByDefault === false) payload.enabled_by_default = false;

  return {
    topic: discoveryTopic("sensor", objectId),
    payload: JSON.stringify(payload),
    retain: true
  };
}

function sensorWithAttributes(objectId, name, valueTemplate, attributesTemplate, options = {}) {
