const topic = String(msg.topic || "");
const value = String(msg.payload ?? "").trim();

const m = topic.match(/^smart_energy_finance\/correction\/([^/]+)\/set$/);
if (!m) return null;

const allowed = [
    "date",

    // sécurité reset all
    "confirmation_reset_all",

    // kWh
    "solar_kwh",
    "load_kwh",
    "grid_import_kwh",
    "grid_export_kwh",
    "battery_charge_kwh",
    "battery_discharge_kwh",

    // €
    "import_cost",
    "export_revenue",
    "theoretical_no_solar_cost",
    "solar_production_value",
    "battery_discharge_value",
    "home_supply_savings",
    "real_total_with_subscription",
    "savings_vs_no_solar"
];

const key = m[1];

if (!allowed.includes(key)) {
    node.warn("Correction key not allowed: " + key);
    return null;
}

global.set(`sef.manual_correction.${key}`, value);

node.status({
    fill: "blue",
    shape: "dot",
    text: `${key} = ${value || "empty"}`
});

return null;

const fs = global.get("fs") || require("fs");

const STORE_FILE = "/config/smart_energy_finance_store.json";
const BACKUP_FILE = "/config/smart_energy_finance_store.backup.json";

const action = String(msg.payload || "apply").trim();
const date = String(global.get("sef.manual_correction.date") || "").trim();

function round(v, d = 2) {
    return Number((Number(v || 0)).toFixed(d));
}

function num(v) {
    if (v === null || v === undefined || v === "") return null;
    const n = Number(String(v).replace(",", "."));
    return Number.isFinite(n) ? n : null;
}

function todayKey() {
    const tz = env.get("ADDON_TIMEZONE") || "UTC";
    const parts = new Intl.DateTimeFormat("en-CA", {
        timeZone: tz,
        year: "numeric",
        month: "2-digit",
        day: "2-digit"
    }).formatToParts(new Date());

    const m = {};
    for (const p of parts) {
        if (p.type !== "literal") m[p.type] = p.value;
    }

    return `${m.year}-${m.month}-${m.day}`;
}

function emptyEnergy() {
    return {
        solar: 0,
        load: 0,
        gridImport: 0,
        gridExport: 0,
        batteryCharge: 0,
        batteryDischarge: 0
    };
}

function emptyFinance() {
    return {
        import_cost: 0,
        export_revenue: 0,
        theoretical_no_solar_cost: 0,
        solar_production_value: 0,
        battery_discharge_value: 0,
        home_supply_savings: 0
    };
}

const fields = [
    "solar_kwh",
    "load_kwh",
    "grid_import_kwh",
    "grid_export_kwh",
    "battery_charge_kwh",
    "battery_discharge_kwh",
    "import_cost",
    "export_revenue",
    "theoretical_no_solar_cost",
    "solar_production_value",
    "battery_discharge_value",
    "home_supply_savings",
    "real_total_with_subscription",
    "savings_vs_no_solar",
    "self_sufficiency_pct",
    "grid_dependency_pct"
];

function loadStoreFromFile(file) {
    if (!fs.existsSync(file)) return null;
    try {
        return JSON.parse(fs.readFileSync(file, "utf8"));
    } catch (e) {
        node.warn("Impossible de lire " + file + ": " + e.message);
        return null;
    }
}

function backupBeforeWrite() {
    if (action === "restore_day") return true;

    try {
        let source = flow.get("finance_store", "persistent") || global.get("sef.persisted_store");

        if (!source && fs.existsSync(STORE_FILE)) {
            source = loadStoreFromFile(STORE_FILE);
        }

        if (!source || typeof source !== "object") {
            node.warn("Backup annulé : store source introuvable");
            return false;
        }

        const backupPayload = JSON.stringify(source, null, 2);
        fs.writeFileSync(BACKUP_FILE, backupPayload, "utf8");

        global.set("sef.manual_correction.last_backup_at", new Date().toISOString());
        node.warn("Backup créé : " + BACKUP_FILE);

        return true;
    } catch (e) {
        node.warn("Erreur création backup : " + e.message);
        return false;
    }
}

function applyDeltaToPeriod(periodArray, key, before, after) {
    const entry = periodArray.find(e => e && e.key === key);
    if (!entry) return;

    for (const f of fields) {
        const delta = Number(after[f] || 0) - Number(before[f] || 0);
        entry[f] = round(Number(entry[f] || 0) + delta, 2);
        if (entry[f] < 0) entry[f] = 0;
    }

    if (Number(entry.load_kwh || 0) > 0) {
        entry.self_sufficiency_pct = round(
            (Math.max(0, Number(entry.load_kwh || 0) - Number(entry.grid_import_kwh || 0)) / Number(entry.load_kwh || 0)) * 100,
            2
        );
        entry.grid_dependency_pct = round(
            (Number(entry.grid_import_kwh || 0) / Number(entry.load_kwh || 0)) * 100,
            2
        );
    } else {
        entry.self_sufficiency_pct = 0;
        entry.grid_dependency_pct = 0;
    }

    entry.manual_adjusted = true;
    entry.manual_adjusted_at = new Date().toISOString();
}

function saveStore(store, status, dateValue) {
    store.meta = store.meta || {};
    store.meta.lastManualCorrectionAt = new Date().toISOString();
    store.meta.lastManualCorrectionAction = action;
    store.meta.lastManualCorrectionDate = dateValue;

    flow.set("finance_store", store, "persistent");
    global.set("sef.persisted_store", store);

    global.set("sef.manual_correction.last_status", status);
    global.set("sef.manual_correction.last_date", dateValue);
    global.set("sef.manual_correction.last_at", new Date().toISOString());

    msg.filename = STORE_FILE;
    msg.payload = JSON.stringify(store, null, 2);

    node.status({
        fill: "green",
        shape: "dot",
        text: `${status} ${dateValue}`
    });

    return msg;
}

let store = flow.get("finance_store", "persistent") || global.get("sef.persisted_store");

if (!store && fs.existsSync(STORE_FILE)) {
    store = loadStoreFromFile(STORE_FILE);
}

if (!store || typeof store !== "object") {
    node.warn("Store introuvable");
    return null;
}

store.history = store.history || {};
store.history.daily = Array.isArray(store.history.daily) ? store.history.daily : [];
store.history.monthly = Array.isArray(store.history.monthly) ? store.history.monthly : [];
store.history.yearly = Array.isArray(store.history.yearly) ? store.history.yearly : [];

if (["apply", "reset_day", "reset_all"].includes(action)) {
    if (!backupBeforeWrite()) {
        node.warn("Action annulée : backup impossible");
        return null;
    }
}

if (action === "reset_day") {
    if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) {
        node.warn("Date invalide pour reset_day");
        return null;
    }

    if (date >= todayKey()) {
        node.warn("Reset journée actuelle refusé");
        return null;
    }

    const entry = store.history.daily.find(d => d && d.key === date);
    if (!entry) {
        node.warn("Date introuvable dans history.daily: " + date);
        return null;
    }

    const before = JSON.parse(JSON.stringify(entry));

    for (const f of fields) {
        entry[f] = 0;
    }

    entry.manual_before = before;
    entry.manual_corrected = true;
    entry.manual_corrected_at = new Date().toISOString();
    entry.manual_correction_type = "reset_day";

    applyDeltaToPeriod(store.history.monthly, date.slice(0, 7), before, entry);
    applyDeltaToPeriod(store.history.yearly, date.slice(0, 4), before, entry);

    return saveStore(store, "reset_day_ok", date);
}

if (action === "restore_day") {
    if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) {
        node.warn("Date invalide pour restore_day");
        return null;
    }

    const backup = loadStoreFromFile(BACKUP_FILE);
    if (!backup || typeof backup !== "object") {
        node.warn("Backup introuvable ou invalide");
        return null;
    }

    backup.history = backup.history || {};
    backup.history.daily = Array.isArray(backup.history.daily) ? backup.history.daily : [];

    const backupEntry = backup.history.daily.find(d => d && d.key === date);
    if (!backupEntry) {
        node.warn("Date introuvable dans le backup: " + date);
        return null;
    }

    let currentEntry = store.history.daily.find(d => d && d.key === date);

    const before = currentEntry
        ? JSON.parse(JSON.stringify(currentEntry))
        : fields.reduce((o, f) => {
            o[f] = 0;
            return o;
        }, { key: date });

    const restored = JSON.parse(JSON.stringify(backupEntry));
    restored.restored_from_backup = true;
    restored.restored_from_backup_at = new Date().toISOString();

    if (currentEntry) {
        Object.keys(currentEntry).forEach(k => delete currentEntry[k]);
        Object.assign(currentEntry, restored);
    } else {
        store.history.daily.push(restored);
        store.history.daily.sort((a, b) => String(a.key).localeCompare(String(b.key)));
        currentEntry = restored;
    }

    applyDeltaToPeriod(store.history.monthly, date.slice(0, 7), before, currentEntry);
    applyDeltaToPeriod(store.history.yearly, date.slice(0, 4), before, currentEntry);

    return saveStore(store, "restore_day_ok", date);
}

if (action === "reset_all") {
    const confirm = String(global.get("sef.manual_correction.confirmation_reset_all") || "").trim();

    if (confirm !== "RESET ALL") {
        node.warn("Reset all refusé : confirmation manquante. Écrire exactement RESET ALL.");

        global.set("sef.manual_correction.last_status", "reset_all_confirmation_required");
        global.set("sef.manual_correction.last_date", "all");
        global.set("sef.manual_correction.last_at", new Date().toISOString());

        node.status({
            fill: "red",
            shape: "ring",
            text: "confirmation RESET ALL required"
        });

        return null;
    }

    // On vide la confirmation après validation pour éviter un 2e reset accidentel
    global.set("sef.manual_correction.confirmation_reset_all", "");

    store.history.daily = [];
    store.history.monthly = [];
    store.history.yearly = [];
    store.history.lastArchivedMonthKey = "";
    store.history.lastArchivedYearKey = "";

    store.closedDayMonthAccumulator = emptyEnergy();
    store.closedDayYearAccumulator = emptyEnergy();
    store.currentDayFinanceAccumulator = emptyFinance();
    store.closedDayMonthFinanceAccumulator = emptyFinance();
    store.closedDayYearFinanceAccumulator = emptyFinance();

    store.currentDaySnapshot = emptyEnergy();
    store.prevLiveDay = emptyEnergy();
    store.lastClosedDayKey = "";

    store.runtime = store.runtime || {};
    store.runtime.initialized = false;
    store.runtime.lastRebaseReason = "manual_reset_all";
    store.runtime.lastRebaseAt = new Date().toISOString();
    store.runtime.restartGuardUntilMs = Date.now() + 120000;

    store.meta = store.meta || {};
    store.meta.lastManualResetAllConfirmedAt = new Date().toISOString();

    return saveStore(store, "reset_all_ok", "all");
}

if (action === "apply") {
    if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) {
        node.warn("Date invalide");
        return null;
    }

    if (date >= todayKey()) {
        node.warn("Impossible de corriger aujourd’hui");
        return null;
    }

    const entry = store.history.daily.find(d => d && d.key === date);
    if (!entry) {
        node.warn("Date introuvable dans history.daily: " + date);
        return null;
    }

    const before = JSON.parse(JSON.stringify(entry));
    let changed = false;

    for (const f of fields) {
        const v = num(global.get(`sef.manual_correction.${f}`));
        if (v !== null) {
            entry[f] = v;
            changed = true;
        }
    }

    if (!changed) {
        node.warn("Aucune valeur à corriger");
        return null;
    }

    if (Number(entry.load_kwh || 0) > 0) {
        entry.self_sufficiency_pct = round(
            (Math.max(0, Number(entry.load_kwh || 0) - Number(entry.grid_import_kwh || 0)) / Number(entry.load_kwh || 0)) * 100,
            2
        );
        entry.grid_dependency_pct = round(
            (Number(entry.grid_import_kwh || 0) / Number(entry.load_kwh || 0)) * 100,
            2
        );
    } else {
        entry.self_sufficiency_pct = 0;
        entry.grid_dependency_pct = 0;
    }

    entry.manual_before = before;
    entry.manual_corrected = true;
    entry.manual_corrected_at = new Date().toISOString();
    entry.manual_correction_type = "manual_apply";

    applyDeltaToPeriod(store.history.monthly, date.slice(0, 7), before, entry);
    applyDeltaToPeriod(store.history.yearly, date.slice(0, 4), before, entry);

    return saveStore(store, "apply_ok", date);
}

node.warn("Action inconnue: " + action);
return null;

const keys = [
